function solve(s: string, k: number): string {
    let result: string[] = [];
    for (let i = 0; i < s.length; i++) {
        const c = s[i];
        if (c === '*') {
            if (result.length > 0) {
                result.pop();
            }
        } else if (c === '#') {
            result = result.concat(result);
        } else if (c === '%') {
            result = result.slice().reverse();
        } else {
            result.push(c);
        }
    }
    if (k < 0 || k >= result.length) {
        return '.';
    }
    return result[k];
}
